```cpp
Bool UnsubscribeDic(String name,String symbol="")
```

**说明：**

> 根据键名和关联名退订基础数据。<br>

**参数：**

| 参数名 | 类型 | 说明 |
| ------ | ---- | ---- |
| name    | String | 基础数据键名 |
| symbol    | String | 基础数据关联名 |

**返回值：**

| 类型 | 说明 |
| ---- | ---- |
| Bool | True表示获取成功，False表示获取失败 |

**示例：**

```cpp
Params
    Bool revOnceRollover(False);

Events
    OnInit()
    {
        SubscribeDic("TB_ROLLOVER_v2",Symbol);
    }


    OnDic(StringRef dicName, StringRef dicSymbol, DicDataRef dicValue)
    {
        if(dicName == "TB_ROLLOVER_v2" &&  dicSymbol == Symbol)
        {
            Array<String> values;
            dicValue.getValue(values);
            Print("dataDateTime = "+Text(dicValue.dataDateTime) + ",pubDateTime="+text(dicValue.pubDateTime)+",data="+TextArray(values));
        }
        if(revOnceRollover)
        {
            UnsubscribeDic("TB_ROLLOVER_v2",Symbol);
        }
    }
